fn gut['r,b](t: &uniq 'r table<K,V>@b, e: own Entry['r,b]) {
  t.insert(k9, v9);   // body entry state: loans(t)={} — LOAN-6(c) seeds nothing; &uniq-receiver op on an unloaned ref binding: ACCEPT (C8's locate does the same); may rehash
  e.fill(v);          // form op 'consumes' on live param e; its loan lookup is vacuous (same as inside C12's finish): ACCEPT — writes through e's interior pointer
}
fn main() {
  let tt = table::new();        // brand btt
  let e  = tt.entry(k);         // loans(tt)={(uniq,e)}
  gut(&uniq tt, own e);         // consuming statement for holder e (LOAN-6a) => LOAN-3 uniq clause's exception ('except within a statement that consumes that loan's holder') and LOAN-4's carve-out ('borrows of the issuer that the op's signature declares') BOTH permit minting &uniq tt; LOAN-7 unifies b := btt from both args (same instance, so brands cannot help); exit: loans(tt)={}
}
// runtime: insert rehashes the table while e's interior pointer is live in the callee; e.fill is a use-after-free write

// Derived per LOAN-6(b): result Entry['r,b] matches own confined param e => REISSUE on e's issuer
